#include <stdio.h>
#include <stdlib.h>

int main() {
    int T, N, i, j;
    int* arr;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        arr = (int*) malloc(N * sizeof(int));
        for (i = 0; i < N; i++) {
            scanf("%d", &arr[i]);
        }
        int xor = 0;
        for (i = 0; i < N; i++) {
            xor ^= arr[i];
        }
        if (xor == 0) {
            printf("Bob\n");
        } else {
            printf("Alice\n");
        }
        free(arr);
    }
    return 0;
}

