const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];

const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const N = parseInt(readline());
    const arr = readline().split(' ').map(x => parseInt(x));
    let xor = 0;
    for (let j = 0; j < N; j++) {
        xor ^= arr[j];
    }
    if (xor == 0) {
        console.log('Bob');
    } else {
        console.log('Alice');
    }
}
